295→/**
296→ * Creates a decision record for collision detection tests.
297→ */
298→export async function createTestDecision(
299→  surreal: Surreal,
300→  workspaceId: string,
301→  overrides: Partial<{
302→    summary: string;
303→    rationale: string;
304→    status: string;
305→    embedding: number[];
