311→
312→  await surreal.query(`CREATE $dec CONTENT $content;`, {
313→    dec: decisionRecord,
314→    content: {
315→      summary: overrides.summary ?? "Test decision for collision detection",
316→      rationale: overrides.rationale ?? "Decided for testing purposes",
317→      status: overrides.status ?? "confirmed",
318→      workspace: workspaceRecord,
319→      created_at: new Date(),
320→      updated_at: new Date(),
321→      ...(overrides.embedding ? { embedding: overrides.embedding } : {}),
322→    },
323→  });
324→
325→  return { decisionId };
