328→/**
329→ * Gets a learning record by ID from SurrealDB.
330→ */
331→export async function getLearningById(
332→  surreal: Surreal,
333→  learningId: string,
334→): Promise<LearningRecord | undefined> {
335→  const learningRecord = new RecordId("learning", learningId);
336→  const rows = (await surreal.query(
337→    `SELECT * FROM $learning;`,
338→    { learning: learningRecord },
339→  )) as Array<LearningRecord[]>;
340→  return rows[0]?.[0];
