402→/**
403→ * Checks whether evidence edges exist for a learning.
404→ */
405→export async function getLearningEvidence(
406→  surreal: Surreal,
407→  learningId: string,
408→): Promise<Array<{ id: RecordId; out: RecordId }>> {
409→  const learningRecord = new RecordId("learning", learningId);
410→  const rows = (await surreal.query(
411→    `SELECT id, out FROM learning_evidence WHERE in = $learning;`,
412→    { learning: learningRecord },
413→  )) as Array<Array<{ id: RecordId; out: RecordId }>>;
414→  return rows[0] ?? [];
415→}
416→
417→/**
418→ * Checks whether a supersedes edge exists between two learnings.
419→ */
420→export async function getSupersessionEdge(
421→  surreal: Surreal,
422→  newLearningId: string,
423→  oldLearningId: string,
424→): Promise<boolean> {
425→  const newRecord = new RecordId("learning", newLearningId);
426→  const oldRecord = new RecordId("learning", oldLearningId);
427→  const rows = (await surreal.query(
428→    `SELECT id FROM supersedes WHERE in = $new AND out = $old;`,
429→    { new: newRecord, old: oldRecord },
430→  )) as Array<Array<{ id: RecordId }>>;
431→  return (rows[0]?.length ?? 0) > 0;
432→}
433→
434→/**
435→ * Generates real embedding vectors using the configured embedding model.
436→ * Returns a map of text -> embedding for seeding test data with real vectors.
437→ */
438→export async function generateEmbeddings(
439→  texts: string[],
440→): Promise<Map<string, number[]>> {
441→  const { embeddings } = await embedMany({
442→    model: testAI.embeddingModel,
443→    values: texts,
444→  });
445→  const result = new Map<string, number[]>();
446→  for (let i = 0; i < texts.length; i++) {
447→    result.set(texts[i], embeddings[i]);
448→  }
449→  return result;
450→}
451→
452→/**
453→ * Generates a real embedding vector for a single text.
454→ */
455→export async function generateEmbedding(text: string): Promise<number[]> {
456→  const map = await generateEmbeddings([text]);
457→  return map.get(text)!;
458→}
459→
460→/**
461→ * Creates a learning with a real embedding generated from its text.
462→ * Convenience wrapper combining createTestLearning + generateEmbedding.
463→ */
464→export async function createTestLearningWithEmbedding(
465→  surreal: Surreal,
466→  workspaceId: string,
467→  overrides: Partial<{
468→    text: string;
469→    learning_type: LearningType;
470→    status: LearningStatus;
471→    source: LearningSource;
472→    priority: LearningPriority;
473→    target_agents: string[];
474→    suggested_by: string;
475→    pattern_confidence: number;
476→    created_by: string;
477→  }> = {},
478→): Promise<{ learningId: string; learningRecord: RecordId<"learning">; embedding: number[] }> {
479→  const text = overrides.text ?? "Default test learning text";
480→  const embedding = await generateEmbedding(text);
481→  const result = await createTestLearning(surreal, workspaceId, {
482→    ...overrides,
483→    text,
484→    embedding,
485→  });
486→  return { ...result, embedding };
487→}
488→
489→/**
490→ * Creates a policy with a real embedding generated from its description.
